// Decode float 2 register -> tegangan
let pay = msg.payload;
if (!Array.isArray(pay) || pay.length < 2) return null;

const buf = Buffer.alloc(4);
// ABCD normal. Kalau tegangan kamu ternyata butuh swap, ganti urutan ini.
buf.writeUInt16BE(pay[0], 0);
buf.writeUInt16BE(pay[1], 2);

const v = buf.readFloatBE(0);
const tegangan = Number(v.toFixed(2));

// Hitung AVG harian di flow context
const now = new Date();
const todayKey = now.getFullYear() + "-" + String(now.getMonth()+1).padStart(2,'0') + "-" + String(now.getDate()).padStart(2,'0');

let data = flow.get('avgV_today') || { date: todayKey, sum: 0, count: 0 };
if (data.date !== todayKey) {
  data = { date: todayKey, sum: 0, count: 0 };
}

data.sum += tegangan;
data.count += 1;
flow.set('avgV_today', data);

const avgToday = Number((data.sum / data.count).toFixed(2));

// Output 1: tegangan
const m1 = { ...msg, payload: tegangan, topic: 'tegangan' };
// Output 2: avgToday
const m2 = { ...msg, payload: avgToday, topic: 'avgToday' };

return [m1, m2];

