const outH = hOk ? Number(h.toFixed(2)) : (Number.isFinite(lastH) ? lastH : null);

// simpan kalau valid
if (tOk) context.set("lastTemp", outT);
if (hOk) context.set("lastHum", outH);

const m1 = { ...msg, payload: outT, topic: "temperatur" };
const m2 = { ...msg, payload: outH, topic: "kelembapan" };

return [m1, m2];

