    data = msg.payload;
} else if (msg.payload.data) {
    data = msg.payload.data;
} else {
    return null;
}

// coba normal order
let v1 = (data[0] << 16) | data[1];
if (v1 & 0x80000000) v1 -= 0x100000000;

// coba swapped order
let v2 = (data[1] << 16) | data[0];
if (v2 & 0x80000000) v2 -= 0x100000000;

// pilih nilai yang masuk akal (>= 0)
let value;
if (v1 >= 0 && v1 <= 100000000) {
    value = v1;
} else if (v2 >= 0 && v2 <= 100000000) {
    value = v2;
} else {
    value = 0; // fallback aman
}

// output watt
msg.payload = value;
// Gabungkan dengan satuan "A"
msg.payload = value + " W";
msg.topic = "L1";

return msg;

