const props = msg.payload?.result?.properties || [];

function pickValue(candidates) {
  for (const code of candidates) {
    const found = props.find(p => p.code === code);
    if (found && found.value !== undefined && found.value !== null) {
      return { code, value: found.value };
    }
  }
  return { code: null, value: null };
}

