  'liquid_depth', 'level_depth', 'water_depth', 'depth', 'distance',
  'level_meter', 'liquid_level_depth'
];
const statusCands = [
  'liquid_level_state', 'level_state', 'water_level_state', 'level_status',
  'status', 'liquid_state'
];

